import { useRef, useCallback } from 'react';
import { useApp } from '../context/AppContext';
import { CalendarEvent } from '../types';
import { SLOT_HEIGHT } from '../utils/dateUtils';

export interface DragState {
  eventId: string;
  /** offset in px from top of the chip where the user grabbed it */
  grabOffsetY: number;
}

export interface UseDragEventReturn {
  draggingId: string | null;
  getChipDragProps: (event: CalendarEvent) => {
    draggable: true;
    onDragStart: (e: React.DragEvent) => void;
    onDragEnd:   (e: React.DragEvent) => void;
  };
  getWeekSlotDropProps: (dateStr: string, hour: number) => {
    onDragOver:  (e: React.DragEvent) => void;
    onDragEnter: (e: React.DragEvent) => void;
    onDrop:      (e: React.DragEvent) => void;
  };
  getMonthCellDropProps: (dateStr: string) => {
    onDragOver:  (e: React.DragEvent) => void;
    onDragEnter: (e: React.DragEvent) => void;
    onDrop:      (e: React.DragEvent) => void;
  };
}

export function useDragEvent(): UseDragEventReturn {
  const { state, dispatch } = useApp();
  const dragState = useRef<DragState | null>(null);
  const draggingIdRef = useRef<string | null>(null);

  // ── Chip drag start ──────────────────────────────────────────────────────────
  const getChipDragProps = useCallback((event: CalendarEvent) => ({
    draggable: true as const,

    onDragStart: (e: React.DragEvent) => {
      // Calculate where inside the chip the user grabbed
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      const grabOffsetY = e.clientY - rect.top;

      dragState.current = { eventId: event.id, grabOffsetY };
      draggingIdRef.current = event.id;

      // Use a transparent drag image so we control the visual via CSS
      const ghost = document.createElement('div');
      ghost.style.cssText = `
        position: fixed; top: -1000px; left: -1000px;
        width: 120px; height: 32px;
        background: ${event.color};
        border-radius: 6px; opacity: 0.85;
        color: white; font-size: 12px;
        display: flex; align-items: center; padding: 0 8px;
        font-family: sans-serif;
        pointer-events: none;
      `;
      ghost.textContent = event.title;
      document.body.appendChild(ghost);
      e.dataTransfer.setDragImage(ghost, 60, 16);
      setTimeout(() => document.body.removeChild(ghost), 0);

      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', event.id);

      // Force a re-render to dim the original chip
      dispatch({ type: 'SET_DRAGGING', payload: event.id });
    },

    onDragEnd: (_e: React.DragEvent) => {
      dragState.current = null;
      draggingIdRef.current = null;
      dispatch({ type: 'SET_DRAGGING', payload: null });
    },
  }), [dispatch]);

  // ── Week slot drop ───────────────────────────────────────────────────────────
  const getWeekSlotDropProps = useCallback((dateStr: string, hour: number) => ({
    onDragOver: (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    },
    onDragEnter: (e: React.DragEvent) => {
      e.preventDefault();
      (e.currentTarget as HTMLElement).classList.add('drag-over');
    },
    onDrop: (e: React.DragEvent) => {
      e.preventDefault();
      (e.currentTarget as HTMLElement).classList.remove('drag-over');

      const ds = dragState.current;
      if (!ds) return;

      const ev = state.events.find(ev => ev.id === ds.eventId);
      if (!ev) return;

      // Calculate the minute offset from the grab position
      const slotRect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      const dropY = e.clientY - slotRect.top + ds.grabOffsetY % SLOT_HEIGHT;
      const minuteOffset = Math.round((dropY / SLOT_HEIGHT) * 60 / 15) * 15; // snap to 15min

      // Build new start time
      const totalMinutes = hour * 60 + Math.min(minuteOffset, 45); // clamp within hour
      const newStartH = Math.floor(totalMinutes / 60) % 24;
      const newStartM = totalMinutes % 60;

      // Keep original duration
      const [oldSH, oldSM] = ev.start.split(':').map(Number);
      const [oldEH, oldEM] = ev.end.split(':').map(Number);
      const durationMin = (oldEH * 60 + oldEM) - (oldSH * 60 + oldSM);

      const newEndTotal = newStartH * 60 + newStartM + durationMin;
      const newEndH = Math.floor(newEndTotal / 60) % 24;
      const newEndM = newEndTotal % 60;

      dispatch({
        type: 'UPDATE_EVENT',
        payload: {
          ...ev,
          date: dateStr,
          start: `${String(newStartH).padStart(2, '0')}:${String(newStartM).padStart(2, '0')}`,
          end:   `${String(newEndH).padStart(2, '0')}:${String(newEndM).padStart(2, '0')}`,
        },
      });
    },
  }), [state.events, dispatch]);

  // ── Month cell drop ──────────────────────────────────────────────────────────
  const getMonthCellDropProps = useCallback((dateStr: string) => ({
    onDragOver: (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    },
    onDragEnter: (e: React.DragEvent) => {
      e.preventDefault();
      (e.currentTarget as HTMLElement).classList.add('drag-over');
    },
    onDrop: (e: React.DragEvent) => {
      e.preventDefault();
      (e.currentTarget as HTMLElement).classList.remove('drag-over');

      const ds = dragState.current;
      if (!ds) return;

      const ev = state.events.find(ev => ev.id === ds.eventId);
      if (!ev) return;

      // In month view just move the date, keep the time
      dispatch({
        type: 'UPDATE_EVENT',
        payload: { ...ev, date: dateStr },
      });
    },
  }), [state.events, dispatch]);

  return {
    draggingId: draggingIdRef.current,
    getChipDragProps,
    getWeekSlotDropProps,
    getMonthCellDropProps,
  };
}
